```typescript
// src/utils/discount.ts

export type DiscountType = "percentage" | "fixed" | "bogo";

type DiscountStrategy = (price: number, value: number) => number;

const discountStrategies: Record<DiscountType, DiscountStrategy> = {
  percentage: (price, value) => price * (1 - value / 100),
  fixed: (price, value) => Math.max(0, price - value),
  bogo: (price, _value) => price / 2,
};

export function calculateDiscount(
  price: number,
  discountType: DiscountType,
  value: number
): number {
  const strategy = discountStrategies[discountType];
  return strategy(price, value);
}
```

